	local MoneyAmount = nil

	local function formatRupiah(num)
		num = tonumber(num) or 0
		local formatted = tostring(num)

		while true do
			formatted, k = formatted:gsub("^(-?%d+)(%d%d%d)", "%1.%2")
			if k == 0 then break end
		end

		return "Rp. "..formatted
	end

